request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelId ?elem1 ?name1 ?type1 ?elem5 ?name5 ?type5 WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "0b4394edaa09437d93cc54c78c0180cb")

  ?elem1 a ?type1 ;
         bbo:name ?name1 ;
         tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?name1)), LCASE("M1")))

  ?elem5 a ?type5 ;
         bbo:name ?name5 ;
         tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?name5)), LCASE("M5")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelId ?m1 ?m5 ?m1Name ?m5Name ?m1Id ?m5Id WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "0b4394edaa09437d93cc54c78c0180cb")

  ?m1 tai:belongsTo ?choreo .
  ?m5 tai:belongsTo ?choreo .

  {
    ?m1 bbo:id ?m1Id .
    FILTER(STRENDS(STR(?m1Id), "M1"))
  }
  UNION
  {
    OPTIONAL { ?m1 bbo:name ?m1Name . }
    FILTER(CONTAINS(STR(?m1Name), "M1"))
  }

  {
    ?m5 bbo:id ?m5Id .
    FILTER(STRENDS(STR(?m5Id), "M5"))
  }
  UNION
  {
    OPTIONAL { ?m5 bbo:name ?m5Name . }
    FILTER(CONTAINS(STR(?m5Name), "M5"))
  }

  OPTIONAL { ?m1 bbo:name ?m1Name . }
  OPTIONAL { ?m5 bbo:name ?m5Name . }

  FILTER(?m1 != ?m5)

  FILTER EXISTS {
    ?m1 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?m5 .
  }
}
LIMIT 25
